function executeFeeSwap(
    address userToken,
    address validatorToken,
    uint256 amountIn
) external returns (uint256 amountOut) {
    bytes32 poolId = getPoolId(userToken, validatorToken);
    Pool storage pool = pools[poolId];

    amountOut = (amountIn * M) / SCALE;

    _requireU128(amountIn);
    _requireU128(amountOut);

    if (pool.reserveValidatorToken < amountOut)
        revert InsufficientLiquidity();

    IERC20(userToken).transferFrom(msg.sender, address(this), amountIn); // EXTERNAL CALL - reentrancy vector

    pool.reserveUserToken += uint128(amountIn);       // STATE UPDATE after external call
    pool.reserveValidatorToken -= uint128(amountOut);  // STATE UPDATE after external call

    IERC20(validatorToken).transfer(msg.sender, amountOut); // Sends real tokens

    emit FeeSwap(userToken, validatorToken, msg.sender, amountIn, amountOut);
}
